import base64
import requests
import uuid
import xml.etree.ElementTree as ET
from datetime import datetime, timedelta
from lxml import etree

class SAMLServiceProvider:
    def __init__(self, destination_url, user_info):
        self.destination_url = destination_url
        self.user_info = user_info
        self.issuer = "https://your-service-provider.com"
        self.id = f"id-{uuid.uuid4()}"
        self.issue_instant = datetime.utcnow().isoformat() + "Z"
        self.expiration_time = (datetime.utcnow() + timedelta(minutes=5)).isoformat() + "Z"

    def create_authn_request(self):
        root = ET.Element("s:AuthnRequest", {
            "xmlns:s": "urn:oasis:names:tc:SAML:2.0:protocol",
            "ID": self.id,
            "Version": "2.0",
            "IssueInstant": self.issue_instant,
            "Destination": self.destination_url,
            "AssertionConsumerServiceURL": "https://your-service-provider.com/acs",
            "ProtocolBinding": "urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST",
            "Issuer": self.issuer
        })

        subject = ET.SubElement(root, "s:Subject")
        name_id = ET.SubElement(subject, "s:NameID")
        name_id.text = self.user_info['username']

        return ET.tostring(root, encoding='utf-8', xml_declaration=True)

    def encode_request(self, xml_request):
        encoded_request = base64.b64encode(xml_request).decode('utf-8')
        return encoded_request

    def send_request(self):
        xml_request = self.create_authn_request()
        encoded_request = self.encode_request(xml_request)

        response = requests.post(self.destination_url, data={
            'SAMLRequest': encoded_request,
            'RelayState': 'some_relay_state'
        })

        return response

